 "proto.tag": "Interoperabilidad",
 "proto.h2": "Habla todos los protocolos que importan",
 "proto.openai": "Sustituye sin cambios <span class=\"mono\">/v1/chat/completions</span>, modelos, embeddings, ejecuciones y sesiones: apunta tus clientes actuales a Jikji.",
 "proto.mcp": "Servidor y cliente de Model Context Protocol por stdio: consume herramientas MCP o expón Jikji como una.",
 "proto.acp": "Agent Communication Protocol por stdio para agentes locales basados en procesos.",
 "proto.a2a": "Colaboración entre agentes: envío de tareas, delegación y recogida de resultados entre agentes.",
 "ops.h": "Herramientas para operadores",
 "ops.p": "<span class=\"mono\">jikjictl</span> abarca credenciales y bóveda, RBAC, políticas, consultas de auditoría, trazas, uso y un marketplace, además de un panel web aparte que nunca guarda claves en el servidor.",
 "term.h": "Nativo de la terminal",
 "term.p": "Chat TUI interactivo, modo de prompt único, flujos de eventos JSONL para automatizar y un modo JSON-RPC al estilo MCP: agentes que puedes encadenar con tuberías.",
 "test.h": "Probado como infraestructura",
 "test.p": "Un control determinista con <span class=\"mono\">make verify</span> y pruebas de humo en vivo, protegidas, contra proveedores reales. Pruebas de rendimiento, fuzzing, propiedades y concurrencia por todo el código.",
 "nav.start": "Empezar",
 "start.h2": "Funcionando en menos de un minuto",
 "cm1": "arranca el servidor (puerto por defecto 1377, sí, ese 1377)",
 "cm2": "comprueba tu entorno local",
 "cm3": "abre el chat TUI interactivo",
 "cm4": "o llama a la API compatible con OpenAI",
 "devnote": "⚠ Jikji está en desarrollo activo y su código fuente aún no es público; pronto será open source. Las APIs y las fronteras entre módulos pueden cambiar antes de la primera versión estable. Esta página describe lo que hoy existe en el código.",
 "foot.tagline": "Tipos móviles para la era de los agentes.",
